import React, { useState, useEffect } from 'react';
import { format, addDays } from 'date-fns';
import { ChevronLeft, ChevronRight, MessageSquare, Sparkles, User, Phone } from 'lucide-react';
import { saveBooking, getBookings } from '../services/api';
import { es } from 'date-fns/locale';

// --- CONSTANTES GLOBALES ---
const INITIAL_AVAILABLE_TIMES = ['09:00 AM', '10:30 AM', '12:00 PM', '02:00 PM', '04:00 PM', '05:30 PM'];
const BASE_SERVICE_TAGS = ['Cl├ísicas 1x1', 'H├¡bridas', 'Volumen 3D', 'Lash Lifting', 'Wispy Style', 'Retoque'];

const ModernScheduler = () => {
  // --- ESTADOS (HOOKS) ---
  const [currentWeekStart, setCurrentWeekStart] = useState(new Date());
  const [selectedDateIndex, setSelectedDateIndex] = useState(0);
  const [selectedTime, setSelectedTime] = useState(null); 
  const [activeServices, setActiveServices] = useState(['Cl├ísicas 1x1']);
  const [notes, setNotes] = useState('');
  const [isFormSubmitted, setIsFormSubmitted] = useState(false);
  const [bookedSlots, setBookedSlots] = useState([]);
  const [isLoadingTimes, setIsLoadingTimes] = useState(true);
  const [nombre, setNombre] = useState('');
  const [whatsapp, setWhatsapp] = useState('');

  // --- EFECTOS (Llamadas a la BD) ---
  useEffect(() => {
    const fetchBookedSlots = async () => {
      setIsLoadingTimes(true);
      try {
        const slots = await getBookings(); 
        setBookedSlots(slots);
      } catch (error) {
        console.error("Error al cargar horarios", error);
      } finally {
        setIsLoadingTimes(false);
      }
    };
    fetchBookedSlots();
  }, [currentWeekStart]);

  // --- L├ôGICA DERIVADA (C├ílculos de Fechas) ---
  const daysToShow = Array.from({ length: 6 }).map((_, i) => addDays(currentWeekStart, i));
  const formatCurrentView = () => format(currentWeekStart, "MMMM yyyy", { locale: es });
  const selectedDateObj = daysToShow[selectedDateIndex];
  const formattedSelectedDate = format(selectedDateObj, 'yyyy-MM-dd');

  // Filtrar disponibilidad real
  const availableTimes = INITIAL_AVAILABLE_TIMES.filter(time => {
    const isOccupied = bookedSlots.some(booking => 
      booking.fecha === formattedSelectedDate && booking.hora === time
    );
    return !isOccupied;
  });

  // --- HANDLERS (Manejadores de Eventos) ---
  const changeWeek = (direction) => {
    setCurrentWeekStart(prev => addDays(prev, direction * 7));
    setSelectedDateIndex(0);
    setSelectedTime(null); 
  };

  const handleDaySelect = (index) => {
    setSelectedDateIndex(index);
    setSelectedTime(null); 
  };

  const toggleService = (service) => {
    setActiveServices(prev => 
      prev.includes(service) ? prev.filter(s => s !== service) : [...prev, service]
    );
  };

  const handleBookingSubmit = async () => {
    if (!selectedTime) {
      alert("Por favor, selecciona una hora para tu cita.");
      return;
    }
    if (!nombre.trim() || !whatsapp.trim()) {
      alert("Por favor, ingresa tu nombre y n├║mero de WhatsApp para poder contactarte.");
      return;
    }
    if (whatsapp.length < 10) {
      alert("Por favor, ingresa un n├║mero de WhatsApp v├ílido (10 d├¡gitos).");
      return;
    }

    setIsLoadingTimes(true);
    try {
      const bookingData = {
        nombre: nombre,
        whatsapp: whatsapp,
        fecha: formattedSelectedDate,
        hora: selectedTime,
        servicio: activeServices.join(', '), 
        notas: notes,
      };
      
      await saveBooking(bookingData);
      alert('┬íCita reservada exitosamente!');
      setIsFormSubmitted(true);
      
      setNombre('');
      setWhatsapp('');
      setNotes('');
      setSelectedTime(null);
      
      const updatedSlots = await getBookings();
      setBookedSlots(updatedSlots);

    } catch (error) {
      alert('Error al reservar. Intenta de nuevo.');
    } finally {
      setIsLoadingTimes(false);
    }
  };

  // --- RENDERIZADO DE INTERFAZ ---
  return (
    <div className="max-w-xl mx-auto p-4 md:p-6 min-h-screen">
      <div className="bg-white p-6 md:p-8 rounded-[2rem] shadow-sm border border-gray-100">
        
        {/* Inicio del renderizado condicional */}
        {isFormSubmitted ? (

          /* Pantalla de ├ëxito y Pago */
          <div className="text-center py-12">
            <div className="w-20 h-20 bg-[#FCE6DF] rounded-full flex items-center justify-center mx-auto mb-4">
              <Sparkles className="text-[#F8E3D7]" size={40} />
            </div>
            <h2 className="text-3xl font-serif font-bold text-gray-900 mb-2">┬íCita Confirmada!</h2>
            <p className="text-gray-600 mb-6">Se recibi├│ tu solicitud. Para confirmar tu cita es necesario realizar un dep├│sito de $250 MXN a la siguiente cuenta: </p>
            <div className="bg-[#Fdfcfb] p-6 rounded-2xl border border-gray-100">
              <p className="text-[10px] font-bold tracking-widest text-gray-400 uppercase mb-4">Datos de Transferencia (SPEI)</p>
              <div className="flex justify-between border-b border-gray-100 pb-2">
                <span className="text-gray-400 font-medium">Banco</span>
                <span className="text-gray-400 font-medium">BBVA</span>
              </div>
              <div className="flex justify-between border-b border-gray-100 pb-2">
                <span className="text-gray-400 font-medium">Beneficiario</span>
                <span className="text-gray-400 font-medium">Gaby L├│pez</span>
              </div>
              <div className="flex justify-between border-b border-gray-100 pb-2">
                <span className="text-gray-400 font-medium">CLABE</span>
                <span className="text-gray-400 font-medium">014180655050579958</span>
              </div>

              <button
              onClick={() => {
                const msj = `┬íHola! He agendado mi cita para ${formattedSelectedDate} a las ${selectedTime}. Te adunto mi comprobante de dep├│sito.`
                window.open(`https://wa.me/4493832267?text=${encodeURIComponent(msj)}`, '_blank');
              }}
              className="w-full bg-[#F8E3D7] text-white py-3 rounded-full font-bold shadow-lg hover:bg-[#f5d4c7] transition-colors hover:scale-[1.02] flex items-center justify-center gap-2"
              >
                <Phone size={18} />
                Enviar comprobante por WhatsApp
              </button>
            </div>
        ) : (
          <>
            {/* SECCI├ôN 1: Ventana de Citas */}
        <div className="mb-10">
          <h2 className="text-2xl font-serif font-bold text-gray-900 mb-6 flex items-center gap-2">
            <Sparkles className="text-[#F8E3D7]" />
            Fecha y Hora <span className="text-[#F8E3D7]">*</span>
          </h2>

          {/* Navegaci├│n de Mes */}
          <div className="flex items-center justify-between mb-5 border border-gray-100 bg-[#Fdfcfb] p-2 rounded-full">
            <div className="capitalize px-4 py-2 bg-white rounded-full shadow-sm flex items-center gap-2 text-sm font-semibold text-gray-800 border border-gray-50">
              {formatCurrentView()} <span className="text-gray-400 text-xs">Ôû╝</span>
            </div>
            <div className="flex gap-2">
              <button onClick={() => changeWeek(-1)} className="p-2 bg-white rounded-full hover:bg-[#FCE6DF] border border-gray-100 transition-colors"><ChevronLeft size={16}/></button>
              <button onClick={() => changeWeek(1)} className="p-2 bg-white rounded-full hover:bg-[#FCE6DF] border border-gray-100 transition-colors"><ChevronRight size={16}/></button>
            </div>
          </div>

          {/* Date Picker Horizontal */}
          <div className="flex gap-3 mb-4 overflow-x-auto pb-2 scrollbar-hide">
            {daysToShow.map((day, index) => {
              const isSelected = index === selectedDateIndex;
              return (
                <button 
                  key={index}
                  onClick={() => handleDaySelect(index)}
                  className={`flex-none w-[70px] h-[70px] rounded-2xl flex flex-col items-center justify-center border transition-all duration-200 
                    ${isSelected 
                      ? 'bg-[#FCE6DF] text-gray-900 shadow-md border-[#FCE6DF] scale-105' 
                      : 'bg-white text-gray-900 hover:border-[#FCE6DF] border-gray-100'}`}
                >
                  <span className={`text-[11px] font-medium uppercase tracking-wider ${isSelected ? 'text-gray-700' : 'text-gray-400'}`}>
                    {format(day, 'eee', { locale: es })}
                  </span>
                  <span className="text-2xl font-bold leading-none mt-1">
                    {format(day, 'dd')}
                  </span>
                </button>
              );
            })}
          </div>

          <p className="text-sm text-gray-400 mb-6 border-b border-gray-100 pb-4 font-medium">Hora Local <span className="text-gray-300 text-xs">Ôû╝</span></p>

          {/* Time Picker Din├ímico */}
          {isLoadingTimes ? (
            <div className="flex justify-center items-center py-8 text-gray-400 text-sm font-semibold">
              <span className="animate-pulse">Sincronizando agenda...</span>
            </div>
          ) : availableTimes.length > 0 ? (
            <div className="grid grid-cols-3 gap-3">
              {availableTimes.map((time) => {
                const isSelected = time === selectedTime;
                return (
                  <button 
                    key={time}
                    onClick={() => setSelectedTime(time)}
                    className={`py-3.5 px-4 rounded-xl text-sm font-semibold transition-all duration-150 border
                      ${isSelected 
                        ? 'bg-[#E2EFE7] text-gray-900 border-[#E2EFE7] shadow-sm scale-105' 
                        : 'bg-white text-gray-700 hover:bg-[#E2EFE7]/30 hover:border-[#E2EFE7] border-gray-100'}`}
                  >
                    {time}
                  </button>
                );
              })}
            </div>
          ) : (
             <div className="text-center py-6 bg-red-50 rounded-xl border border-red-100">
               <p className="text-red-500 font-semibold text-sm">Agenda llena para este d├¡a</p>
               <p className="text-xs text-red-400 mt-1">Por favor selecciona otra fecha arriba.</p>
             </div>
          )}
        </div>

        {/* SECCI├ôN 2: Detalles del Cliente y Servicio */}
        <div className="border-t border-gray-100 pt-8">
          <h2 className="text-2xl font-serif font-bold text-gray-900 mb-6 flex items-center gap-2">
            <User className="text-[#F8E3D7]" />
            Tus Datos y Servicios <span className="text-[#F8E3D7]">*</span>
          </h2>
          
          <p className="text-sm text-gray-500 mb-5">Ingresa tu informaci├│n de contacto para confirmar tu espacio.</p>

          {/* INPUTS DE CONTACTO */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-5">
            <div className="relative">
              <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
              <input 
                type="text" 
                value={nombre}
                onChange={(e) => setNombre(e.target.value)}
                placeholder="Nombre completo *" 
                className="w-full pl-11 pr-4 py-3 border border-gray-100 rounded-xl bg-gray-50/50 text-sm focus:ring-2 focus:ring-[#FCE6DF] focus:border-[#FCE6DF] outline-none transition-all"
                required
              />
            </div>
            <div className="relative">
              <Phone className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
              <input 
                type="tel" 
                value={whatsapp}
                onChange={(e) => setWhatsapp(e.target.value)}
                placeholder="WhatsApp (10 d├¡gitos) *" 
                className="w-full pl-11 pr-4 py-3 border border-gray-100 rounded-xl bg-gray-50/50 text-sm focus:ring-2 focus:ring-[#FCE6DF] focus:border-[#FCE6DF] outline-none transition-all"
                required
              />
            </div>
          </div>

          {/* Input de Notas */}
          <div className="relative mb-6">
            <MessageSquare className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input 
              type="text" 
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Notas adicionales (Ej. Tengo dise├▒o anterior)..." 
              className="w-full pl-11 pr-4 py-3 border border-gray-100 rounded-xl bg-gray-50/50 text-sm focus:ring-2 focus:ring-[#FCE6DF] focus:border-[#FCE6DF] outline-none transition-all"
            />
          </div>

          {/* Selector de Tags */}
          <div className="flex flex-wrap gap-2.5 mb-8">
            {BASE_SERVICE_TAGS.map(service => {
              const isActive = activeServices.includes(service);
              return (
                <button
                  key={service}
                  onClick={() => toggleService(service)}
                  className={`px-4 py-2.5 rounded-full text-xs font-semibold flex items-center gap-1.5 transition-all border
                    ${isActive 
                      ? 'bg-[#FCE6DF] text-gray-900 border-[#FCE6DF] shadow-sm' 
                      : 'bg-white text-gray-600 hover:border-[#FCE6DF] hover:bg-[#FCE6DF]/10 border-gray-200'}`}
                >
                  {service} {isActive && <span className="text-gray-600 ml-1">├ù</span>}
                </button>
              )
            })}
          </div>

          {/* FOOTER ACTIONS */}
          <div className="flex justify-end gap-3 pt-6 border-t border-gray-100 mt-10">
            <button 
              onClick={() => { setNombre(''); setWhatsapp(''); setNotes(''); setActiveServices(['Cl├ísicas 1x1']); setSelectedTime(null); }}
              className="px-6 py-3 rounded-full text-sm font-semibold text-gray-600 hover:bg-[#FCE6DF]/50 hover:text-gray-900 transition-colors"
            >
              Limpiar
            </button>
            <button 
              onClick={handleBookingSubmit}
              disabled={isLoadingTimes || !selectedTime || activeServices.length === 0}
              className="px-10 py-3 rounded-full text-sm font-semibold bg-gray-900 text-white hover:bg-gray-800 shadow-lg shadow-gray-900/20 disabled:bg-gray-200 disabled:text-gray-400 disabled:shadow-none transition-all"
            >
              {isLoadingTimes ? 'Guardando...' : 'Agendar Cita'}
            </button>
          </div>
        </div>
          </>
        )}
      </div>
    </div>
  );
};

export default ModernScheduler;
